8	  Schema.isLessThanOrEqualTo(400),
9	);
10	const TerminalRowsSchema = Schema.Int.check(Schema.isGreaterThanOrEqualTo(5)).check(
11	  Schema.isLessThanOrEqualTo(200),
12	);
13	const TerminalIdSchema = TrimmedNonEmptyStringSchema.check(Schema.isMaxLength(128));
14	const TerminalEnvKeySchema = Schema.String.check(
15	  Schema.isPattern(/^[A-Za-z_][A-Za-z0-9_]*$/),
16	).check(Schema.isMaxLength(128));
17	const TerminalEnvValueSchema = Schema.String.check(Schema.isMaxLength(8_192));
18	const TerminalEnvSchema = Schema.Record(TerminalEnvKeySchema, TerminalEnvValueSchema).check(
19	  Schema.isMaxProperties(128),
20	);
21	
22	const TerminalIdWithDefaultSchema = TerminalIdSchema.pipe(
23	  Schema.withDecodingDefault(() => DEFAULT_TERMINAL_ID),
24	);
25	
26	export const TerminalThreadInput = Schema.Struct({
27	  threadId: TrimmedNonEmptyStringSchema,
28	});
29	export type TerminalThreadInput = Schema.Codec.Encoded<typeof TerminalThreadInput>;
30	
31	const TerminalSessionInput = Schema.Struct({
32	  ...TerminalThreadInput.fields,
33	  terminalId: TerminalIdWithDefaultSchema,
34	});
35	export type TerminalSessionInput = Schema.Codec.Encoded<typeof TerminalSessionInput>;
36	
37	export const TerminalOpenInput = Schema.Struct({
38	  ...TerminalSessionInput.fields,
39	  cwd: TrimmedNonEmptyStringSchema,
40	  cols: Schema.optional(TerminalColsSchema),
