42	  env: Schema.optional(TerminalEnvSchema),
43	});
44	export type TerminalOpenInput = Schema.Codec.Encoded<typeof TerminalOpenInput>;
45	
46	export const TerminalWriteInput = Schema.Struct({
47	  ...TerminalSessionInput.fields,
48	  data: Schema.String.check(Schema.isNonEmpty()).check(Schema.isMaxLength(65_536)),
49	});
50	export type TerminalWriteInput = Schema.Codec.Encoded<typeof TerminalWriteInput>;
51	
52	export const TerminalResizeInput = Schema.Struct({
53	  ...TerminalSessionInput.fields,
54	  cols: TerminalColsSchema,
55	  rows: TerminalRowsSchema,
56	});
57	export type TerminalResizeInput = Schema.Codec.Encoded<typeof TerminalResizeInput>;
58	
59	export const TerminalClearInput = TerminalSessionInput;
60	export type TerminalClearInput = Schema.Codec.Encoded<typeof TerminalClearInput>;
61	
62	export const TerminalRestartInput = Schema.Struct({
63	  ...TerminalThreadInput.fields,
64	  cwd: TrimmedNonEmptyStringSchema,
65	  cols: TerminalColsSchema,
66	  rows: TerminalRowsSchema,
67	  env: Schema.optional(TerminalEnvSchema),
68	});
69	
70	export const TerminalCloseInput = Schema.Struct({
