}

export interface ThemeDefinition {
  readonly id: ThemeId;
  readonly name: string;
  readonly colorScheme: "dark" | "light";
  readonly colors: ThemeColors;
}

export const THEMES: Record<ThemeId, ThemeDefinition> = {
  "t3-dark": {
    id: "t3-dark",
    name: "T3 Dark",
    colorScheme: "dark",
    colors: {
      background: "#0f0f11",
