    },
  },
};

export const THEME_IDS: readonly ThemeId[] = ["t3-dark", "t3-light", "t3-midnight"];
export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

export function isThemeId(value: unknown): value is ThemeId {
  return value === "t3-dark" || value === "t3-light" || value === "t3-midnight";
