          >
            {/* Mini editor preview */}
            <div
              className="h-16 w-32 overflow-hidden rounded-lg"
              style={{ background: def.colors.background }}
              aria-hidden="true"
            >
              <div className="flex h-full">
                {/* Sidebar strip */}
                <div className="h-full w-8 shrink-0" style={{ background: def.colors.sidebar }} />
                <div className="flex min-w-0 flex-1 flex-col">
