                    <div className="h-1 w-8 rounded-full" style={{ background: def.colors.accent }} />
                    <div className="mt-1 h-1 w-12 rounded-full opacity-40" style={{ background: def.colors.foreground }} />
                    <div className="mt-1 h-1 w-6 rounded-full opacity-25" style={{ background: def.colors.foreground }} />
