```

---

## Step 3 — `apps/web/src/components/ThemeProvider.tsx` (new)

Mirrors the module-level store pattern from existing `hooks/useTheme.ts` and `appSettings.ts`. Adds React Context on top. Apply theme immediately on module load (flash prevention).

```typescript
import {
  createContext,
  useCallback,
  useContext,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import {
  DEFAULT_THEME_ID,
  THEME_IDS,
  getTheme,
  isThemeId,
  type ThemeDefinition,
  type ThemeId,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:app-theme";

let listeners: Array<() => void> = [];
let lastThemeId: ThemeId | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getStoredThemeId(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  return isThemeId(raw) ? raw : DEFAULT_THEME_ID;
}

function applyTheme(id: ThemeId, suppressTransitions = false): void {
  const theme = getTheme(id);
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  document.documentElement.dataset["theme"] = id;
  document.documentElement.classList.toggle("dark", theme.colorScheme === "dark");
  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStoredThemeId());

function getSnapshot(): ThemeId {
  const id = getStoredThemeId();
  if (lastThemeId === id) return lastThemeId;
  lastThemeId = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStoredThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);
  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

interface ThemeContextValue {
  themeId: ThemeId;
  themeDefinition: ThemeDefinition;
  setTheme: (id: ThemeId) => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const themeDefinition = getTheme(themeId);
  const setTheme = useCallback((id: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyTheme(id, true);
    emitChange();
  }, []);

  return (
    // React 19 shorthand — no .Provider needed
    <ThemeContext value={{ themeId, themeDefinition, setTheme }}>
      {children}
    </ThemeContext>
  );
}

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error("useTheme must be used inside ThemeProvider");
  return ctx;
}

// Re-export types/data consumers may need
export type { ThemeId, ThemeDefinition } from "@t3tools/shared/theme";
export { THEME_IDS, THEMES, getTheme } from "@t3tools/shared/theme";
```

**Note on `THEME_IDS` import**: `THEME_IDS` is imported from `@t3tools/shared/theme` — the `ThemeSelector` uses it to iterate themes, but doesn't need to import it again since `ThemeProvider` re-exports it.

---

## Step 4 — `apps/web/src/hooks/useTheme.ts` (full replacement)

Replace every line of the existing file with a thin re-export shim so existing import paths keep working:

```typescript
export { useTheme, ThemeProvider } from "../components/ThemeProvider";
export type { ThemeId, ThemeDefinition } from "../components/ThemeProvider";
```

The old `Theme = "light" | "dark" | "system"` union and old `{ theme, setTheme, resolvedTheme }` return shape are removed. The only consumer (`_chat.settings.tsx`) is updated in Step 8.

---

## Step 5 — `apps/web/src/components/ThemeSelector.tsx` (new)

Renders a row of clickable swatch cards. Each swatch is a mini editor mockup built from inline styles using the theme's color values (no Tailwind utilities for colors — these are dynamic JS values).

```typescript
import { useTheme, THEME_IDS, getTheme } from "../hooks/useTheme";

export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="flex flex-wrap gap-3" role="radiogroup" aria-label="Theme">
      {THEME_IDS.map((id) => {
        const def = getTheme(id);
        const selected = themeId === id;
        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setTheme(id)}
            className={[
              "flex flex-col gap-2 rounded-xl border p-3 text-left transition-shadow",
              "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:ring-offset-background",
              selected
                ? "border-primary/60 bg-primary/8 ring-1 ring-primary/40"
                : "border-border bg-background hover:bg-accent",
            ].join(" ")}
          >
            {/* Mini editor preview */}
            <div
              className="h-16 w-32 overflow-hidden rounded-lg"
              style={{ background: def.colors.background }}
              aria-hidden="true"
            >
              <div className="flex h-full">
                {/* Sidebar strip */}
                <div className="h-full w-8 shrink-0" style={{ background: def.colors.sidebar }} />
                <div className="flex min-w-0 flex-1 flex-col">
                  {/* Status bar */}
                  <div className="h-2 w-full shrink-0" style={{ background: def.colors.statusBar }} />
                  {/* Editor fill with accent lines */}
                  <div className="flex-1 px-1.5 pt-2" style={{ background: def.colors.editor }}>
                    <div className="h-1 w-8 rounded-full" style={{ background: def.colors.accent }} />
                    <div className="mt-1 h-1 w-12 rounded-full opacity-40" style={{ background: def.colors.foreground }} />
                    <div className="mt-1 h-1 w-6 rounded-full opacity-25" style={{ background: def.colors.foreground }} />
                  </div>
                  {/* Terminal strip */}
                  <div className="h-5 w-full shrink-0" style={{ background: def.colors.terminal }} />
                </div>
              </div>
            </div>

            {/* Label */}
            <div className="flex items-center justify-between gap-2">
              <span className="text-xs font-medium text-foreground">{def.name}</span>
              {selected && (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}
```

---

## Step 6 — `apps/web/src/index.css` (append)

Append these three blocks at the very end of the file. Selector `:root[data-theme="..."]` has specificity 0-1-1 (`:root` pseudo-class + attribute selector), matching the dark-variant compiled form. Placed after the existing `:root { @variant dark {...} }` block, they win the cascade for any element with a `data-theme` attribute.

