### 4.6 WEBSOCKET SCHEMAS (packages/contracts/src/ws.ts)

**Pattern: Tagged request bodies + Schema.Struct.mapFields**

```typescript
const tagRequestBody = <const Tag extends string, const Fields extends Schema.Struct.Fields>(
  tag: Tag,
  schema: Schema.Struct<Fields>,
) =>
  schema.mapFields(
    Struct.assign({ _tag: Schema.tag(tag) }),
    { unsafePreserveChecks: true },
  );

const WebSocketRequestBody = Schema.Union([
  tagRequestBody(ORCHESTRATION_WS_METHODS.dispatchCommand, ...),
  tagRequestBody(ORCHESTRATION_WS_METHODS.getSnapshot, ...),
  // ... 20+ tagged request types
]);

export const WebSocketRequest = Schema.Struct({
  id: TrimmedNonEmptyString,
  body: WebSocketRequestBody,
});
```

