import { useTheme, THEME_IDS, getTheme } from "../hooks/useTheme";

export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="flex flex-wrap gap-3" role="radiogroup" aria-label="Theme">
      {THEME_IDS.map((id) => {
        const def = getTheme(id);
        const selected = themeId === id;
        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => setTheme(id)}
            className={[
              "flex flex-col gap-2 rounded-xl border p-3 text-left transition-shadow",
              "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:ring-offset-background",
              selected
                ? "border-primary/60 bg-primary/8 ring-1 ring-primary/40"
                : "border-border bg-background hover:bg-accent",
            ].join(" ")}
          >
            {/* Mini editor preview */}
            <div
              className="h-16 w-32 overflow-hidden rounded-lg"
              style={{ background: def.colors.background }}
              aria-hidden="true"
            >
              <div className="flex h-full">
                {/* Sidebar strip */}
                <div className="h-full w-8 shrink-0" style={{ background: def.colors.sidebar }} />
                <div className="flex min-w-0 flex-1 flex-col">
                  {/* Status bar */}
                  <div
                    className="h-2 w-full shrink-0"
                    style={{ background: def.colors.statusBar }}
                  />
                  {/* Editor fill with accent/foreground lines */}
                  <div
                    className="flex-1 px-1.5 pt-2"
                    style={{ background: def.colors.editor }}
                  >
                    <div
                      className="h-1 w-8 rounded-full"
                      style={{ background: def.colors.accent }}
                    />
                    <div
                      className="mt-1 h-1 w-12 rounded-full opacity-40"
                      style={{ background: def.colors.foreground }}
                    />
                    <div
                      className="mt-1 h-1 w-6 rounded-full opacity-25"
                      style={{ background: def.colors.foreground }}
                    />
                  </div>
                  {/* Terminal strip */}
                  <div
                    className="h-5 w-full shrink-0"
                    style={{ background: def.colors.terminal }}
                  />
                </div>
              </div>
            </div>

            {/* Label row */}
            <div className="flex items-center justify-between gap-2">
              <span className="text-xs font-medium text-foreground">{def.name}</span>
              {selected && (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}

